import SwiftUI
import CoreBluetooth

// REQUIRES PLIST: NSBluetoothAlwaysUsageDescription
class BluetoothViewModel: NSObject, ObservableObject, CBCentralManagerDelegate {
    private var centralManager: CBCentralManager!
    @Published var isBluetoothReady = false
    @Published var statusMessage: String?
    @Published var discoveredPeripherals: [String] = []
    @Published var isScanning = false
    private var discoveredIDs = Set<UUID>()

    override init() {
        super.init()
        centralManager = CBCentralManager(delegate: self, queue: nil)
    }

    func centralManager(_ central: CBCentralManager, didUpdateState state: CBManagerState) {
        DispatchQueue.main.async {
            switch state {
            case .poweredOn:
                self.isBluetoothReady = true
                self.statusMessage = nil
            default:
                self.isBluetoothReady = false
                self.statusMessage = "Bluetooth is off or unavailable"
            }
        }
    }

    func centralManager(_ central: CBCentralManager, didDiscover peripheral: CBPeripheral, advertisementData: [String: Any], rssi RSSI: NSNumber) {
        DispatchQueue.main.async {
            guard !self.discoveredIDs.contains(peripheral.identifier) else { return }
            self.discoveredIDs.insert(peripheral.identifier)
            self.discoveredPeripherals.append(peripheral.name ?? peripheral.identifier.uuidString)
        }
    }

    func startScan() {
        guard isBluetoothReady else { return }
        discoveredPeripherals = []
        discoveredIDs = []
        isScanning = true
        centralManager.scanForPeripherals(withServices: nil)
    }
}

struct BluetoothView: View {
    @StateObject private var viewModel = BluetoothViewModel()

    var body: some View {
        VStack(spacing: 16) {
            if let message = viewModel.statusMessage {
                Text(message).foregroundStyle(.secondary)
            }
            Button("Scan") { viewModel.startScan() }
                .disabled(!viewModel.isBluetoothReady)
            if viewModel.isScanning && viewModel.discoveredPeripherals.isEmpty {
                Text("Scanning...").foregroundStyle(.secondary)
            }
            List(viewModel.discoveredPeripherals, id: \.self) { name in
                Text(name)
            }
        }
    }
}
